mapper.select:
/* wms-outbound-obMoveObManager-sql-oracle.xml - selectContainerCountMoveOutboundUnConfirmed - 출고헤더 별 미확정 용기 카운트 조회 */
SELECT
	SUM(CASE WHEN MC.CNFRMYN = 'N' THEN 1 ELSE 0 END) CNT
FROM TWORK_INFO_OB_HD OBHD
	INNER JOIN TWORK_INFO_MVOB_CNTR MC /*이고 용기 정보*/
		ON OBHD.CTKEY = MC.CTKEY
		AND OBHD.OWKEY = MC.OWKEY
		AND OBHD.OBHDKEY = MC.OBHDKEY
WHERE OBHD.CTKEY = #{ctkey}
AND OBHD.OWKEY = #{owkey}
AND OBHD.OBHDKEY = #{obhdkey}
AND MC.CNTRDDLNYN = 'Y'
AND OBHD.CNTRWKCOMPLYN = 'Y'

/* wms-outbound-obMoveObManager-sql-oracle.xml - selectPickingDetailListByOutboundConfirmed - 출고확정에 의한 PICKTO 재고차감 대상 조회 */
SELECT
	CTKEY
	,OWKEY
	,IVATKEY
	,ICKEY
	,LCKEY
	,(CNFRMQTY - OBCNFRMQTY - RVSQTY) AS REMAINQTY
	,PIHDKEY
	,PIDTKEY
	,OBHDKEY
	,OBDTKEY
FROM TWORK_INFO_PI_DT
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND OBHDKEY = #{obhdkey}
AND OBDTKEY = #{obdtkey}
AND ICKEY = #{ickey}
AND IVATKEY = #{ivatkey}
AND (CNFRMQTY - OBCNFRMQTY - RVSQTY) > 0
AND PKDTWKSTATUSCD = '10'
ORDER BY IVATKEY, LCKEY

mapper.update:
/* wms-outbound-obMoveObManager-sql-oracle.xml - updateMoveOutboundContainerConfirm - 이고용기 출고확정처리 */
UPDATE TWORK_INFO_MVOB_CNTR
SET CNFRMYN = 'Y'
	,CNFRMDATE = #{sysdate}
	,CNFRMURKEY = #{surkey}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND CNTRBARCODE = #{cntrbarcode}

/* wms-outbound-obMoveObManager-sql-oracle.xml - updateMoveOutboundDetailNisQty - 이고용기 출고확정처리 */
UPDATE TWORK_INFO_OB_DT
SET NISQTY = NISQTY + #{nisqty}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND OBDTKEY = #{obdtkey}
